er.code:
erDiagram
  USER ||--o{ DIAGRAM : creates
  DIAGRAM ||--o{ EXPORT : produces
  USER {
    string id
    string email
  }
  DIAGRAM {
    string type
    string source
  }

class.code:
@startuml
class Diagram {
  +source: string
  +render(): SVG
}
class PlantUMLDiagram
Diagram <|-- PlantUMLDiagram
@enduml

usecase.code:
@startuml
left to right direction
actor Developer
rectangle DiagramPreview {
  Developer -- (Preview PlantUML)
  Developer -- (Export SVG)
}
@enduml

activity.code:
@startuml
start
:Paste source;
if (Valid?) then (yes)
  :Render preview;
else (no)
  :Show error;
endif
stop
@enduml

digraph.code:
digraph G {
  rankdir=LR;
  Start -> Parse -> Render -> Export;
  Render -> Error;
  Error -> Parse;
}

dependency.code:
digraph dependencies {
  node [shape=box, style=rounded];
  app -> ui;
  app -> renderers;
  renderers -> mermaid;
  renderers -> graphviz;
}

state.code:
digraph states {
  node [shape=circle];
  editing -> rendering;
  rendering -> ready;
  rendering -> failed;
  failed -> editing;
}
